import React from 'react';

import AppCore from '../AppCore';
import MyPcConfigRenderer from './Pages/MyPcConfigRenderer';
import MyPcExperienceRenderer from './Pages/MyPcExperienceRenderer';
import MyPcSetupRenderer from './Pages/MyPcSetupRenderer';

const MyPc = React.forwardRef(({ iconX, iconY, parentRef, ...others }, ref) => {
	return (
		<AppCore
			AppRenderer={{
				config: MyPcConfigRenderer,
				setup: MyPcSetupRenderer,
				experience: MyPcExperienceRenderer,
			}}
			iconX={iconX}
			iconY={iconY}
			title="myPc"
			icon="icons/pc.png"
			width={530}
			height={450}
			backgroundColor="#cbcbcb"
			topBarColor="#01009b"
			titleColor="white"
			ref={ref}
			parentRef={parentRef}
			overflowY="hidden"
			options={["config", "setup", "experience"]}
			initialOption="config"
			{...others}
		/>
	);
});

export default MyPc;
